var RangeFreqQuery = function(arr) {
    this.pos = new Map();
    for (let i = 0; i < arr.length; i++) {
        const v = arr[i];
        if (!this.pos.has(v)) this.pos.set(v, []);
        this.pos.get(v).push(i);
    }
};
RangeFreqQuery.prototype.query = function(left, right, value) {
    const list = this.pos.get(value);
    if (!list) return 0;
    let lo = 0, hi = list.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (list[mid] < left) lo = mid + 1; else hi = mid;
    }
    const start = lo;
    lo = 0; hi = list.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (list[mid] <= right) lo = mid + 1; else hi = mid;
    }
    return lo - start;
};
